// src/embedding/ollama.ts
var DEFAULT_ENDPOINT = "http://localhost:11434";
function createOllamaEmbedding(config) {
  const endpoint = config.endpoint ?? DEFAULT_ENDPOINT;
  const url = `${endpoint}/api/embed`;
  async function requestEmbeddings(input) {
    const response = await fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ model: config.model, input })
    });
    if (!response.ok) {
      const body = await response.text();
      throw new Error(`Ollama embed failed (${response.status}): ${body}`);
    }
    const data = await response.json();
    return data.embeddings;
  }
  return {
    dimensions: config.dimensions,
    async embed(text) {
      const embeddings = await requestEmbeddings(text);
      const first = embeddings[0];
      if (!first)
        throw new Error("no embedding returned from Ollama");
      return first;
    },
    async embedBatch(texts) {
      return requestEmbeddings(texts);
    }
  };
}
// src/embedding/index.ts
function createEmbeddingProvider(config) {
  switch (config.provider) {
    case "ollama":
      return createOllamaEmbedding(config);
    default:
      throw new Error(`Unknown embedding provider: ${String(config.provider)}`);
  }
}

